89	type Policy = { items: Item[]; cap: number; remainingCap: number };
90	
91	const insuranceSumFor = (items: Item[]): number =>
92	  items.reduce((sum, item) => sum + INSURANCE_VALUES[item.type], 0);
93	
94	const processClaim = (step: any, policies: Policy[]): { payout: number; remainingCap: number } => {
95	  const policy = policies[step.policy];
96	  const payout = step.incident.damages.reduce(
97	    (total: number, damage: any) => total + Math.max(0, damage.amount - DEDUCTIBLE_PER_DAMAGE),
98	    0,
99	  );
100	  const flooredPayout = Math.floor(payout);
101	  policy.remainingCap -= flooredPayout;
102	  return { payout: flooredPayout, remainingCap: policy.remainingCap };
103	};
104	
105	export function processScenario(scenario: any): unknown {
106	  const policies: Policy[] = [];
107	  const results = scenario.steps.map((step: any, index: number) => {
108	    if (step.type === "claim") {
109	      return processClaim(step, policies);
110	    }
111	    const insuranceSum = insuranceSumFor(step.items);
112	    const cap = CAP_MULTIPLIER * insuranceSum;
113	    policies.push({ items: step.items, cap, remainingCap: cap });
114	    return {
115	      premium: quotePremium(step.items, scenario.customer, index > 0),
116	    };
117	  });
118	  return { results };
119	}
